/**
 * Response-body validation (data contract checks).
 *
 * Upptime's native site check only asserts the HTTP status code, so an endpoint
 * that returns 200 with empty / malformed / wrong-shaped data still shows green.
 * This script closes that gap: it calls every monitored REST endpoint with the
 * appropriate API key and validates the *response body* against a per-endpoint
 * contract defined in response-validation.config.js.
 *
 * Severity model:
 *   - HARD checks  -> a failure fails the CI job (real data regression:
 *                     wrong status, broken JSON, missing/mistyped fields,
 *                     identity mismatch, empty stable datasets).
 *   - SOFT checks  -> a failure is reported as a WARNING only (things that can
 *                     legitimately vary, e.g. realtime quote/trade arrays being
 *                     sparse outside market hours, or the known Search `cik`
 *                     NaN quirk). Warnings never fail the job.
 *
 * Usage:  node .github/scripts/validate-response-bodies.js
 * Env:    PRIXE_API_KEY, PRIXE_PRO_API_KEY, PRIXE_PRO_PLUS_API_KEY (per endpoint)
 *         RESPONSE_VALIDATION_RESULT_FILE (optional, JSON results output path)
 * Exit:   0 if all endpoints pass their HARD checks, 1 otherwise.
 *
 * This file is NOT regenerated by Upptime's update-template workflow.
 */

const fs = require('fs');
const path = require('path');

const ENDPOINTS = require('./response-validation.config.js');

const REQUEST_TIMEOUT_MS = 35000;
const CONCURRENCY = 6;
const RESULT_FILE = process.env.RESPONSE_VALIDATION_RESULT_FILE ||
  path.join(__dirname, '../../response-validation-result.json');

// ---------------------------------------------------------------------------
// JSON parsing (tolerant, but records strict validity)
// ---------------------------------------------------------------------------

function parseBody(raw) {
  // strictValid is false if the payload contains non-standard tokens such as
  // bare NaN / Infinity (invalid per RFC 8259 — JS JSON.parse rejects them).
  let strictValid = true;
  let value;
  try {
    value = JSON.parse(raw);
  } catch (e) {
    strictValid = false;
    try {
      const sanitized = raw
        .replace(/\bNaN\b/g, 'null')
        .replace(/-?\bInfinity\b/g, 'null');
      value = JSON.parse(sanitized);
    } catch (e2) {
      return { strictValid: false, parseable: false, value: undefined };
    }
  }
  return { strictValid, parseable: true, value };
}

// ---------------------------------------------------------------------------
// Path resolver: dot keys, [index], and `*` (first entry of an object map/array)
// ---------------------------------------------------------------------------

function resolvePath(root, pathStr) {
  const tokens = pathStr
    .replace(/\[(\d+)\]/g, '.$1')
    .split('.')
    .filter((t) => t !== '');
  let cur = root;
  for (const tok of tokens) {
    if (cur === null || cur === undefined) return { found: false };
    if (tok === '*') {
      if (Array.isArray(cur)) {
        if (cur.length === 0) return { found: false };
        cur = cur[0];
      } else if (typeof cur === 'object') {
        const keys = Object.keys(cur);
        if (keys.length === 0) return { found: false };
        cur = cur[keys[0]];
      } else {
        return { found: false };
      }
    } else {
      if (typeof cur !== 'object') return { found: false };
      if (!(tok in cur)) return { found: false };
      cur = cur[tok];
    }
  }
  return { found: true, value: cur };
}

function typeOf(v) {
  if (Array.isArray(v)) return 'array';
  if (v === null) return 'null';
  return typeof v;
}

// ---------------------------------------------------------------------------
// Single-check evaluation -> null if pass, else a human-readable reason string
// ---------------------------------------------------------------------------

function evalCheck(root, check) {
  const { found, value } = resolvePath(root, check.path);
  if (!found) return `missing "${check.path}"`;

  if (check.type) {
    const actual = typeOf(value);
    if (check.type === 'integer') {
      if (typeof value !== 'number' || !Number.isInteger(value)) {
        return `"${check.path}" expected integer, got ${actual}`;
      }
    } else if (actual !== check.type) {
      return `"${check.path}" expected ${check.type}, got ${actual}`;
    }
  }
  if (Object.prototype.hasOwnProperty.call(check, 'equals')) {
    if (value !== check.equals) {
      return `"${check.path}" expected ${JSON.stringify(check.equals)}, got ${JSON.stringify(value)}`;
    }
  }
  if (check.nonEmpty) {
    if ((typeof value === 'string' || Array.isArray(value)) && value.length === 0) {
      return `"${check.path}" is empty`;
    }
  }
  if (typeof check.minLength === 'number') {
    if (!(typeof value === 'string' || Array.isArray(value)) || value.length < check.minLength) {
      const len = value && value.length != null ? value.length : 'n/a';
      return `"${check.path}" length ${len} < ${check.minLength}`;
    }
  }
  if (typeof check.minKeys === 'number') {
    if (typeOf(value) !== 'object' || Object.keys(value).length < check.minKeys) {
      return `"${check.path}" expected >= ${check.minKeys} keys`;
    }
  }
  if (typeof check.gt === 'number') {
    if (typeof value !== 'number' || !(value > check.gt)) {
      return `"${check.path}" expected > ${check.gt}, got ${JSON.stringify(value)}`;
    }
  }
  if (typeof check.min === 'number') {
    if (typeof value !== 'number' || !(value >= check.min)) {
      return `"${check.path}" expected >= ${check.min}, got ${JSON.stringify(value)}`;
    }
  }
  if (check.match) {
    if (typeof value !== 'string' || !new RegExp(check.match).test(value)) {
      return `"${check.path}" did not match /${check.match}/ (got ${JSON.stringify(value)})`;
    }
  }
  return null;
}

// ---------------------------------------------------------------------------
// Per-endpoint validation
// ---------------------------------------------------------------------------

async function validateEndpoint(ep) {
  const result = {
    name: ep.name,
    url: ep.url,
    method: ep.method,
    httpStatus: null,
    timeMs: null,
    ok: false,
    hardFailures: [],
    warnings: [],
  };

  const key = process.env[ep.keyEnv];
  if (!key) {
    result.hardFailures.push(`secret ${ep.keyEnv} is not set`);
    return result;
  }

  const headers = { Authorization: `Bearer ${key}` };
  const init = { method: ep.method, headers };
  if (ep.method === 'POST') {
    headers['Content-Type'] = 'application/json';
    init.body = JSON.stringify(ep.body || {});
  }

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
  const start = Date.now();
  let raw;
  try {
    const res = await fetch(ep.url, { ...init, signal: controller.signal });
    result.httpStatus = res.status;
    raw = await res.text();
  } catch (e) {
    result.timeMs = Date.now() - start;
    result.hardFailures.push(`request failed: ${e.name === 'AbortError' ? 'timeout' : e.message}`);
    return result;
  } finally {
    clearTimeout(timer);
  }
  result.timeMs = Date.now() - start;

  const expectStatus = ep.expectStatus || 200;
  if (result.httpStatus !== expectStatus) {
    result.hardFailures.push(`HTTP ${result.httpStatus} (expected ${expectStatus})`);
    result.bodyPreview = (raw || '').slice(0, 160);
    return result;
  }

  const parsed = parseBody(raw);
  if (!parsed.parseable) {
    result.hardFailures.push('response body is not parseable JSON');
    result.bodyPreview = (raw || '').slice(0, 160);
    return result;
  }
  if (!parsed.strictValid) {
    const msg = 'response is not strict-valid JSON (contains NaN/Infinity tokens)';
    if (ep.requireStrictJson === false) result.warnings.push(msg);
    else result.hardFailures.push(msg);
  }

  for (const check of ep.checks || []) {
    const reason = evalCheck(parsed.value, check);
    if (reason) {
      if (check.severity === 'soft') result.warnings.push(reason);
      else result.hardFailures.push(reason);
    }
  }

  result.ok = result.hardFailures.length === 0;
  return result;
}

// ---------------------------------------------------------------------------
// Concurrency pool
// ---------------------------------------------------------------------------

async function runPool(items, size, worker) {
  const results = new Array(items.length);
  let next = 0;
  async function run() {
    while (next < items.length) {
      const i = next++;
      results[i] = await worker(items[i], i);
    }
  }
  await Promise.all(Array.from({ length: Math.min(size, items.length) }, run));
  return results;
}

// ---------------------------------------------------------------------------
// Reporting
// ---------------------------------------------------------------------------

function writeStepSummary(results, failed) {
  const file = process.env.GITHUB_STEP_SUMMARY;
  if (!file) return;
  const lines = [];
  lines.push(`## Response-body validation — ${results.length - failed}/${results.length} passed`);
  lines.push('');
  lines.push('| Status | Endpoint | HTTP | Time | Notes |');
  lines.push('|---|---|---|---|---|');
  for (const r of results) {
    const icon = r.ok ? '✅' : '❌';
    const notes = [
      ...r.hardFailures.map((f) => `**${f}**`),
      ...r.warnings.map((w) => `_warn: ${w}_`),
    ].join('; ') || '—';
    lines.push(`| ${icon} | ${r.name} | ${r.httpStatus ?? '-'} | ${r.timeMs ?? '-'}ms | ${notes} |`);
  }
  try {
    fs.appendFileSync(file, lines.join('\n') + '\n');
  } catch (e) {
    console.error('Could not write step summary:', e.message);
  }
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

(async () => {
  console.log(`Validating ${ENDPOINTS.length} endpoint response bodies...\n`);
  const results = await runPool(ENDPOINTS, CONCURRENCY, validateEndpoint);

  let failed = 0;
  let warned = 0;
  for (const r of results) {
    if (!r.ok) failed++;
    if (r.warnings.length) warned++;
    const icon = r.ok ? '✓' : '✗';
    const tail = r.ok ? '' : '  ->  ' + r.hardFailures.join('; ');
    console.log(`${icon} ${r.name.padEnd(40)} HTTP ${String(r.httpStatus ?? '-').padEnd(4)} ${String(r.timeMs ?? '-').padStart(6)}ms${tail}`);
    for (const w of r.warnings) console.log(`    ⚠ ${w}`);
  }

  console.log(`\n${results.length - failed}/${results.length} passed hard checks, ${warned} with warnings.`);

  try {
    fs.writeFileSync(RESULT_FILE, JSON.stringify({
      generatedAt: new Date().toISOString(),
      total: results.length,
      passed: results.length - failed,
      failed,
      warned,
      results,
    }, null, 2));
    console.log('Wrote results to', RESULT_FILE);
  } catch (e) {
    console.error('Could not write result file:', e.message);
  }

  writeStepSummary(results, failed);

  if (failed > 0) {
    console.error(`\n✗ ${failed} endpoint(s) failed response-body validation.`);
    process.exitCode = 1;
  } else {
    console.log('\n✓ All endpoints returned valid, correctly-shaped data.');
  }
})();
